@page "/"

<PageTitle>RecipeShare - Home</PageTitle>

<h1>🍳 Welcome to RecipeShare</h1>
<p class="lead">Discover and share delicious recipes from around the world.</p>

<h2>Browse by Category</h2>

<div class="row">
    @foreach (var category in Categories)
    {
        <div class="col-md-4 mb-4">
            <div class="card h-100">
                <div class="card-body">
                    <h5 class="card-title">@GetCategoryEmoji(category) @category</h5>
                    <p class="card-text">@GetCategoryDescription(category)</p>
                    <a href="recipes/@category" class="btn btn-primary">View Recipes</a>
                </div>
            </div>
        </div>
    }
</div>

@code {
    [Inject] private RecipeShare.Services.RecipeService RecipeService { get; set; } = default!;

    private IReadOnlyList<string> Categories { get; set; } = [];

    protected override void OnInitialized()
    {
        Categories = RecipeService.GetCategories();
    }

    private static string GetCategoryEmoji(string category) => category switch
    {
        "Italian" => "🍝",
        "Indian" => "🍛",
        "Mexican" => "🌮",
        "Thai" => "🍜",
        "Desserts" => "🍰",
        "Salads" => "🥗",
        _ => "🍽️"
    };

    private static string GetCategoryDescription(string category) => category switch
    {
        "Italian" => "Classic pasta, pizza, and Mediterranean flavors.",
        "Indian" => "Rich curries, aromatic spices, and vibrant dishes.",
        "Mexican" => "Bold flavors with fresh salsas and tortillas.",
        "Thai" => "Sweet, sour, salty, and spicy balance.",
        "Desserts" => "Indulgent sweets and baked treats.",
        "Salads" => "Fresh, crisp, and healthy options.",
        _ => "Explore delicious recipes."
    };
}

@page "/recipes"
@page "/recipes/{Category}"

<PageTitle>Recipes @(Category is not null ? $"- {Category}" : "") | RecipeShare</PageTitle>

<h1>@(Category is not null ? $"{Category} Recipes" : "All Recipes")</h1>

@if (Category is not null)
{
    <p><a href="recipes">← Back to all recipes</a></p>
}

<div class="row">
    @foreach (var recipe in Recipes)
    {
        <div class="col-md-6 mb-4">
            <div class="card h-100">
                <div class="card-body">
                    <h5 class="card-title">@recipe.Title</h5>
                    <span class="badge bg-secondary mb-2">@recipe.Category</span>
                    @if (recipe.RatingCount > 0)
                    {
                        <p class="text-warning mb-1">
                            @for (int i = 1; i <= 5; i++)
                            {
                                @(i <= Math.Round(recipe.AverageRating) ? "★" : "☆")
                            }
                            <small class="text-muted">(@recipe.RatingCount ratings)</small>
                        </p>
                    }
                    <a href="recipe/@recipe.Id" class="btn btn-outline-primary">View Recipe</a>
                </div>
            </div>
        </div>
    }
</div>

@code {
    [Parameter] public string? Category { get; set; }
    [Inject] private RecipeShare.Services.RecipeService RecipeService { get; set; } = default!;

    private IReadOnlyList<RecipeShare.Models.Recipe> Recipes { get; set; } = [];

    protected override void OnInitialized()
    {
        Recipes = Category is not null
            ? RecipeService.GetRecipesByCategory(Category)
            : RecipeService.GetAllRecipes();
    }
}

@page "/recipe/{Id:int}"

<PageTitle>@(Recipe?.Title ?? "Recipe") | RecipeShare</PageTitle>

@if (Recipe is null)
{
    <h1>Recipe not found</h1>
    <p><a href="recipes">← Browse all recipes</a></p>
}
else
{
    <h1>@Recipe.Title</h1>
    <span class="badge bg-secondary mb-3">@Recipe.Category</span>

    <div class="row mt-3">
        <div class="col-md-4">
            <div class="card">
                <div class="card-header"><strong>Ingredients</strong></div>
                <div class="card-body">
                    <ul class="list-unstyled mb-0">
                        @foreach (var ingredient in Recipe.Ingredients.Split('\n', StringSplitOptions.RemoveEmptyEntries))
                        {
                            <li>• @ingredient</li>
                        }
                    </ul>
                </div>
            </div>
        </div>

        <div class="col-md-8">
            <div class="card">
                <div class="card-header"><strong>Instructions</strong></div>
                <div class="card-body">
                    @foreach (var step in Recipe.Steps.Split('\n', StringSplitOptions.RemoveEmptyEntries))
                    {
                        <p>@step</p>
                    }
                </div>
            </div>
        </div>
    </div>

    <div class="mt-4">
        <h4>Rate this recipe</h4>
        <StarRating RecipeId="@Recipe.Id" CurrentAverage="@Recipe.AverageRating" RatingCount="@Recipe.RatingCount" />
    </div>

    <p class="mt-3"><a href="recipes/@Recipe.Category">← Back to @Recipe.Category recipes</a></p>
}

@code {
    [Parameter] public int Id { get; set; }
    [Inject] private RecipeShare.Services.RecipeService RecipeService { get; set; } = default!;

    private RecipeShare.Models.Recipe? Recipe { get; set; }

    protected override void OnInitialized()
    {
        Recipe = RecipeService.GetRecipeById(Id);
    }
}

@rendermode InteractiveServer

<div class="star-rating">
    @for (int i = 1; i <= 5; i++)
    {
        var star = i;
        <span class="star @(star <= (_hoverRating > 0 ? _hoverRating : (int)Math.Round(CurrentAverage)) ? "filled" : "")"
              @onclick="() => SubmitRating(star)"
              @onmouseover="() => _hoverRating = star"
              @onmouseout="() => _hoverRating = 0"
              style="cursor: pointer; font-size: 1.8rem;">
            @(star <= (_hoverRating > 0 ? _hoverRating : (int)Math.Round(CurrentAverage)) ? "★" : "☆")
        </span>
    }
    <span class="ms-2 text-muted">
        @if (_submitted)
        {
            <text>Thanks for rating!</text>
        }
        else
        {
            <text>(@RatingCount ratings, avg @CurrentAverage.ToString("F1"))</text>
        }
    </span>
</div>

@code {
    [Parameter] public int RecipeId { get; set; }
    [Parameter] public double CurrentAverage { get; set; }
    [Parameter] public int RatingCount { get; set; }
    [Inject] private RecipeShare.Services.RecipeService RecipeService { get; set; } = default!;

    private int _hoverRating;
    private bool _submitted;

    private void SubmitRating(int stars)
    {
        if (_submitted) return;

        RecipeService.AddRating(RecipeId, stars);
        var recipe = RecipeService.GetRecipeById(RecipeId);
        if (recipe is not null)
        {
            CurrentAverage = recipe.AverageRating;
            RatingCount = recipe.RatingCount;
        }
        _submitted = true;
    }
}

@page "/submit"
@rendermode InteractiveServer

<PageTitle>Submit a Recipe | RecipeShare</PageTitle>

<h1>Submit a Recipe</h1>
<p>Share your favorite recipe with the community!</p>

@if (_submitted)
{
    <div class="alert alert-success">
        <strong>Recipe submitted!</strong> Your recipe "<strong>@_model.Title</strong>" has been added.
        <a href="recipe/@_submittedId">View it here</a>.
    </div>
    <button class="btn btn-primary" @onclick="Reset">Submit Another</button>
}
else
{
    <EditForm Model="_model" OnValidSubmit="HandleSubmit" FormName="submitRecipe">
        <DataAnnotationsValidator />
        <ValidationSummary class="text-danger" />

        <div class="mb-3">
            <label for="title" class="form-label">Recipe Title</label>
            <InputText id="title" class="form-control" @bind-Value="_model.Title" placeholder="e.g., Grandma's Apple Pie" />
            <ValidationMessage For="() => _model.Title" />
        </div>

        <div class="mb-3">
            <label for="category" class="form-label">Category</label>
            <InputSelect id="category" class="form-select" @bind-Value="_model.Category">
                <option value="">-- Select a category --</option>
                <option value="Italian">Italian</option>
                <option value="Indian">Indian</option>
                <option value="Mexican">Mexican</option>
                <option value="Thai">Thai</option>
                <option value="Desserts">Desserts</option>
                <option value="Salads">Salads</option>
            </InputSelect>
            <ValidationMessage For="() => _model.Category" />
        </div>

        <div class="mb-3">
            <label for="ingredients" class="form-label">Ingredients (one per line)</label>
            <InputTextArea id="ingredients" class="form-control" rows="6" @bind-Value="_model.Ingredients" placeholder="2 cups flour&#10;1 cup sugar&#10;3 eggs" />
            <ValidationMessage For="() => _model.Ingredients" />
        </div>

        <div class="mb-3">
            <label for="steps" class="form-label">Steps (one per line)</label>
            <InputTextArea id="steps" class="form-control" rows="6" @bind-Value="_model.Steps" placeholder="1. Preheat oven to 350°F&#10;2. Mix dry ingredients&#10;3. Add wet ingredients" />
            <ValidationMessage For="() => _model.Steps" />
        </div>

        <button type="submit" class="btn btn-success">Submit Recipe</button>
    </EditForm>
}

@code {
    [Inject] private RecipeShare.Services.RecipeService RecipeService { get; set; } = default!;

    private RecipeFormModel _model = new();
    private bool _submitted;
    private int _submittedId;

    private void HandleSubmit()
    {
        var recipe = new RecipeShare.Models.Recipe
        {
            Title = _model.Title,
            Category = _model.Category,
            Ingredients = _model.Ingredients,
            Steps = _model.Steps
        };
        RecipeService.AddRecipe(recipe);
        _submittedId = recipe.Id;
        _submitted = true;
    }

    private void Reset()
    {
        _model = new();
        _submitted = false;
    }

    private class RecipeFormModel
    {
        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Title is required.")]
        [System.ComponentModel.DataAnnotations.StringLength(100)]
        public string Title { get; set; } = string.Empty;

        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Please select a category.")]
        public string Category { get; set; } = string.Empty;

        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Ingredients are required.")]
        public string Ingredients { get; set; } = string.Empty;

        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Steps are required.")]
        public string Steps { get; set; } = string.Empty;
    }
}

